class SecretManager {
  constructor() {
    this._secrets = new Map();
    this._encryptionKey = process.env.ENCRYPTION_KEY
      ? Buffer.from(process.env.ENCRYPTION_KEY, 'hex')
      : crypto.randomBytes(32);
  }

  setSecret(key, value) {
    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv('aes-256-gcm', this._encryptionKey, iv);
    let encrypted = cipher.update(value, 'utf8', 'hex');
    encrypted += cipher.final('hex');
    const authTag = cipher.getAuthTag();
    this._secrets.set(key, { encrypted, iv: iv.toString('hex'), authTag: authTag.toString('hex') });
  }

  getSecret(key) {
    const data = this._secrets.get(key);
    if (!data) return null;
    const decipher = crypto.createDecipheriv(
      'aes-256-gcm',
      this._encryptionKey,
      Buffer.from(data.iv, 'hex')
    );
    decipher.setAuthTag(Buffer.from(data.authTag, 'hex'));
    let decrypted = decipher.update(data.encrypted, 'hex', 'utf8');
    decrypted += decipher.final('utf8');
    return decrypted;
  }
}

